    97тЖТ      const message = error.message.toLowerCase();
    98тЖТ      return (
    99тЖТ        message.includes('network') ||
   100тЖТ        message.includes('timeout') ||
   101тЖТ        message.includes('econnrefused') ||
   102тЖТ        message.includes('econnreset') ||
   103тЖТ        message.includes('socket hang up')
   104тЖТ      );
   105тЖТ    }
   106тЖТ
   107тЖТ    return false;
   108тЖТ  },
   109тЖТ};
   110тЖТ
   111тЖТ/**
   112тЖТ * Default function to determine if an error is retryable
   113тЖТ */
   114тЖТfunction defaultIsRetryable(error: unknown): boolean {
   115тЖТ  // Don't retry validation errors or not found errors
   116тЖТ  if (error instanceof Error) {
   117тЖТ    const code = (error as Error & { code?: string }).code ?? '';
   118тЖТ    const statusCode = (error as Error & { statusCode?: number }).statusCode ?? 0;
   119тЖТ
   120тЖТ    // Don't retry 4xx client errors (except 408 timeout, 429 rate limit)
   121тЖТ    if (statusCode >= 400 && statusCode < 500 && statusCode !== 408 && statusCode !== 429) {
   122тЖТ      return false;
   123тЖТ    }
   124тЖТ
   125тЖТ    // Don't retry certain error codes
   126тЖТ    if (code.startsWith('BUS_') || code.startsWith('AUTH_')) {
   127тЖТ      return false;
   128тЖТ    }
   129тЖТ  }
   130тЖТ
   131тЖТ  return true;
   132тЖТ}
   133тЖТ
   134тЖТ/**
   135тЖТ * Calculate delay for a given attempt with optional jitter
   136тЖТ */
   137тЖТfunction calculateDelay(attempt: number, config: RetryConfig): number {
   138тЖТ  const exponentialDelay = config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1);
   139тЖТ  let delay = Math.min(exponentialDelay, config.maxDelayMs);
   140тЖТ
   141тЖТ  if (config.jitter) {
   142тЖТ    // Add ┬▒25% jitter
   143тЖТ    const jitterRange = delay * 0.25;
   144тЖТ    delay = delay - jitterRange + Math.random() * jitterRange * 2;
   145тЖТ  }
   146тЖТ
   147тЖТ  return Math.round(delay);
   148тЖТ}
   149тЖТ
   150тЖТ/**
   151тЖТ * Sleep for a specified duration
   152тЖТ */
   153тЖТfunction sleep(ms: number): Promise<void> {
   154тЖТ  return new Promise((resolve) => setTimeout(resolve, ms));
   155тЖТ}
   156тЖТ
   157тЖТ/**
   158тЖТ * Execute a function with retry logic
   159тЖТ *
   160тЖТ * Uses exponential backoff with optional jitter to handle transient failures.
   161тЖТ * Integrates with OpenTelemetry tracing for observability.
   162тЖТ *
   163тЖТ * @example
   164тЖТ * ```typescript
   165тЖТ * const result = await withRetry(
   166тЖТ *   async () => {
   167тЖТ *     return await fetchFromMaximo('/api/workorders');
   168тЖТ *   },
   169тЖТ *   {
   170тЖТ *     maxAttempts: 5,
   171тЖТ *     initialDelayMs: 1000,
   172тЖТ *     isRetryable: (error) => error instanceof NetworkError
   173тЖТ *   },
   174тЖТ *   'fetchWorkOrders'
   175тЖТ * );
   176тЖТ * ```
   177тЖТ */
   178тЖТexport async function withRetry<T>(
   179тЖТ  fn: () => Promise<T>,
   180тЖТ  config?: Partial<RetryConfig>,
   181тЖТ  operationName?: string
   182тЖТ): Promise<T> {
   183тЖТ  const opts = { ...DEFAULT_RETRY_CONFIG, ...config };
   184тЖТ  const name = operationName ?? 'retry';
   185тЖТ
   186тЖТ  return withSpan(
   187тЖТ    `resilience.${name}`,
   188тЖТ    async (span) => {
   189тЖТ      span.setAttribute('retry.max_attempts', opts.maxAttempts);
   190тЖТ      let lastError: unknown;
   191тЖТ
   192тЖТ      for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
   193тЖТ        try {
   194тЖТ          span.setAttribute('retry.current_attempt', attempt);
   195тЖТ          addSpanEvent('retry.attempt', { attempt });
   196тЖТ
   197тЖТ          const result = await fn();
   198тЖТ
   199тЖТ          if (attempt > 1) {
   200тЖТ            addSpanEvent('retry.success', { attempt, totalAttempts: attempt });
   201тЖТ          }
   202тЖТ
   203тЖТ          return result;
   204тЖТ        } catch (error) {
   205тЖТ          lastError = error;
   206тЖТ
   207тЖТ          // Check if we should retry
   208тЖТ          const shouldRetry = attempt < opts.maxAttempts && (opts.isRetryable?.(error) ?? true);
   209тЖТ
   210тЖТ          if (!shouldRetry) {
   211тЖТ            addSpanEvent('retry.exhausted', {
   212тЖТ              attempt,
   213тЖТ              error: error instanceof Error ? error.message : String(error),
   214тЖТ              retryable: opts.isRetryable?.(error) ?? true,
   215тЖТ            });
   216тЖТ            throw error;
   217тЖТ          }
   218тЖТ
   219тЖТ          // Calculate delay
   220тЖТ          const delayMs = calculateDelay(attempt, opts);
   221тЖТ
   222тЖТ          addSpanEvent('retry.waiting', {
   223тЖТ            attempt,
   224тЖТ            delayMs,
   225тЖТ            error: error instanceof Error ? error.message : String(error),
   226тЖТ          });
   227тЖТ
   228тЖТ          // Invoke callback if provided
   229тЖТ          opts.onRetry?.(error, attempt, delayMs);
   230тЖТ
   231тЖТ          logger.warn(
   232тЖТ            {
   233тЖТ              operation: name,
   234тЖТ              attempt,
   235тЖТ              nextAttempt: attempt + 1,
   236тЖТ              delayMs,
   237тЖТ              error: error instanceof Error ? error.message : String(error),
   238тЖТ            },
   239тЖТ            `Retry attempt ${attempt}/${opts.maxAttempts} failed, waiting ${delayMs}ms`
   240тЖТ          );
   241тЖТ
   242тЖТ          await sleep(delayMs);
   243тЖТ        }
   244тЖТ      }
   245тЖТ
   246тЖТ      // Should never reach here, but TypeScript needs this
   247тЖТ      throw lastError;
   248тЖТ    },
   249тЖТ    { kind: SpanKind.INTERNAL }
   250тЖТ  );
   251тЖТ}
   252тЖТ
   253тЖТ// =============================================================================
   254тЖТ// Circuit Breaker Implementation
   255тЖТ// =============================================================================
   256тЖТ
   257тЖТ/**
   258тЖТ * Circuit breaker states
   259тЖТ */
   260тЖТexport type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';
   261тЖТ
   262тЖТ/**
   263тЖТ * Circuit breaker configuration
   264тЖТ */
   265тЖТexport interface CircuitBreakerConfig {
   266тЖТ  /** Number of failures before opening the circuit */
   267тЖТ  failureThreshold: number;
   268тЖТ  /** Number of successes in half-open state to close circuit */
   269тЖТ  successThreshold: number;
   270тЖТ  /** Time to wait before transitioning from OPEN to HALF_OPEN (ms) */
   271тЖТ  resetTimeoutMs: number;
   272тЖТ  /** Function to determine if an error counts as a failure */
   273тЖТ  isFailure?: (error: unknown) => boolean;
   274тЖТ  /** Callback when circuit state changes */
   275тЖТ  onStateChange?: (from: CircuitState, to: CircuitState) => void;
   276тЖТ}
   277тЖТ
   278тЖТ/**
   279тЖТ * Default circuit breaker configuration
   280тЖТ */
   281тЖТexport const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
   282тЖТ  failureThreshold: 5,
   283тЖТ  successThreshold: 3,
   284тЖТ  resetTimeoutMs: 30000,
   285тЖТ  isFailure: () => true,
   286тЖТ};
   287тЖТ
   288тЖТ/**
   289тЖТ * Circuit breaker metrics
   290тЖТ */
   291тЖТexport interface CircuitBreakerMetrics {
   292тЖТ  state: CircuitState;
   293тЖТ  failures: number;
   294тЖТ  successes: number;
   295тЖТ  lastFailureTime: Date | null;
   296тЖТ  lastSuccessTime: Date | null;
   297тЖТ  totalRequests: number;
   298тЖТ  totalFailures: number;
   299тЖТ  totalSuccesses: number;
   300тЖТ}
   301тЖТ
   302тЖТ/**
   303тЖТ * Circuit Breaker implementation
   304тЖТ *
   305тЖТ * Prevents cascading failures by stopping requests to a failing service.
   306тЖТ * Implements the standard circuit breaker pattern:
   307тЖТ * - CLOSED: Normal operation, requests flow through
   308тЖТ * - OPEN: Failures exceeded threshold, requests fail fast
   309тЖТ * - HALF_OPEN: Testing if service has recovered
   310тЖТ *
   311тЖТ * @example
   312тЖТ * ```typescript
   313тЖТ * const maximoBreaker = new CircuitBreaker({
   314тЖТ *   failureThreshold: 5,
   315тЖТ *   resetTimeoutMs: 30000,
   316тЖТ *   onStateChange: (from, to) => {
   317тЖТ *     logger.warn({ from, to }, 'Maximo circuit breaker state changed');
   318тЖТ *   }
   319тЖТ * }, 'maximo');
   320тЖТ *
   321тЖТ * // In service
   322тЖТ * const result = await maximoBreaker.execute(
   323тЖТ *   async () => fetchFromMaximo('/api/workorders')
   324тЖТ * );
   325тЖТ * ```
   326тЖТ */
   327тЖТexport class CircuitBreaker {
   328тЖТ  private state: CircuitState = 'CLOSED';
   329тЖТ  private failures = 0;
   330тЖТ  private successes = 0;
   331тЖТ  private lastFailureTime: Date | null = null;
   332тЖТ  private lastSuccessTime: Date | null = null;
   333тЖТ  private totalRequests = 0;
   334тЖТ  private totalFailures = 0;
   335тЖТ  private totalSuccesses = 0;
   336тЖТ  private readonly config: CircuitBreakerConfig;
   337тЖТ  private readonly name: string;
   338тЖТ  private readonly log: typeof logger;
   339тЖТ
   340тЖТ  constructor(config: Partial<CircuitBreakerConfig> = {}, name = 'default') {
   341тЖТ    this.config = { ...DEFAULT_CIRCUIT_BREAKER_CONFIG, ...config };
   342тЖТ    this.name = name;
   343тЖТ    this.log = logger.child({ circuitBreaker: name });
   344тЖТ  }
   345тЖТ
   346тЖТ  /**
   347тЖТ   * Execute a function through the circuit breaker
   348тЖТ   */
   349тЖТ  async execute<T>(fn: () => Promise<T>): Promise<T> {
   350тЖТ    return withSpan(
   351тЖТ      `circuitBreaker.${this.name}`,
   352тЖТ      async (span) => {
   353тЖТ        span.setAttribute('circuit_breaker.name', this.name);
   354тЖТ        span.setAttribute('circuit_breaker.state', this.state);
   355тЖТ
   356тЖТ        this.totalRequests++;
   357тЖТ
   358тЖТ        // Check if circuit should transition from OPEN to HALF_OPEN
   359тЖТ        this.checkResetTimeout();
   360тЖТ
   361тЖТ        // If circuit is OPEN, fail fast
   362тЖТ        if (this.state === 'OPEN') {
   363тЖТ          addSpanEvent('circuit_breaker.rejected', { state: this.state });
   364тЖТ          throw new ServiceUnavailableError(
   365тЖТ            `Circuit breaker ${this.name} is OPEN. Service unavailable.`,
   366тЖТ            { retryAfter: Math.ceil(this.config.resetTimeoutMs / 1000) }
   367тЖТ          );
   368тЖТ        }
   369тЖТ
   370тЖТ        try {
   371тЖТ          const result = await fn();
   372тЖТ          this.recordSuccess();
   373тЖТ          addSpanEvent('circuit_breaker.success', { state: this.state });
   374тЖТ          return result;
   375тЖТ        } catch (error) {
   376тЖТ          if (this.config.isFailure?.(error) ?? true) {
   377тЖТ            this.recordFailure();
   378тЖТ            addSpanEvent('circuit_breaker.failure', {
   379тЖТ              state: this.state,
   380тЖТ              failures: this.failures,
   381тЖТ            });
   382тЖТ          }
   383тЖТ          throw error;
   384тЖТ        }
   385тЖТ      },
   386тЖТ      { kind: SpanKind.INTERNAL }
   387тЖТ    );
   388тЖТ  }
   389тЖТ
   390тЖТ  /**
   391тЖТ   * Check if the reset timeout has elapsed and transition to HALF_OPEN
   392тЖТ   */
   393тЖТ  private checkResetTimeout(): void {
   394тЖТ    if (this.state !== 'OPEN' || !this.lastFailureTime) return;
   395тЖТ
   396тЖТ    const elapsed = Date.now() - this.lastFailureTime.getTime();
   397тЖТ    if (elapsed >= this.config.resetTimeoutMs) {
   398тЖТ      this.transition('HALF_OPEN');
   399тЖТ    }
   400тЖТ  }
   401тЖТ
   402тЖТ  /**
   403тЖТ   * Record a successful execution
   404тЖТ   */
   405тЖТ  private recordSuccess(): void {
   406тЖТ    this.successes++;
   407тЖТ    this.totalSuccesses++;
   408тЖТ    this.lastSuccessTime = new Date();
   409тЖТ
   410тЖТ    if (this.state === 'HALF_OPEN') {
   411тЖТ      if (this.successes >= this.config.successThreshold) {
   412тЖТ        this.transition('CLOSED');
   413тЖТ      }
   414тЖТ    } else if (this.state === 'CLOSED') {
   415тЖТ      // Reset failure count on success in CLOSED state
   416тЖТ      this.failures = 0;
   417тЖТ    }
   418тЖТ  }
   419тЖТ
   420тЖТ  /**
   421тЖТ   * Record a failed execution
   422тЖТ   */
   423тЖТ  private recordFailure(): void {
   424тЖТ    this.failures++;
   425тЖТ    this.totalFailures++;
   426тЖТ    this.lastFailureTime = new Date();
   427тЖТ    this.successes = 0; // Reset success count on failure
   428тЖТ
   429тЖТ    if (this.state === 'HALF_OPEN') {
   430тЖТ      // Any failure in HALF_OPEN opens the circuit again
   431тЖТ      this.transition('OPEN');
   432тЖТ    } else if (this.state === 'CLOSED') {
   433тЖТ      if (this.failures >= this.config.failureThreshold) {
   434тЖТ        this.transition('OPEN');
   435тЖТ      }
   436тЖТ    }
   437тЖТ  }
   438тЖТ
   439тЖТ  /**
   440тЖТ   * Transition to a new state
   441тЖТ   */
   442тЖТ  private transition(to: CircuitState): void {
   443тЖТ    const from = this.state;
   444тЖТ    if (from === to) return;
   445тЖТ
   446тЖТ    this.log.info({ from, to }, `Circuit breaker transitioning: ${from} -> ${to}`);
   447тЖТ
   448тЖТ    this.state = to;
   449тЖТ    this.failures = 0;
   450тЖТ    this.successes = 0;
   451тЖТ
   452тЖТ    this.config.onStateChange?.(from, to);
   453тЖТ  }
   454тЖТ
   455тЖТ  /**
   456тЖТ   * Get current circuit breaker metrics
   457тЖТ   */
   458тЖТ  getMetrics(): CircuitBreakerMetrics {
   459тЖТ    return {
   460тЖТ      state: this.state,
   461тЖТ      failures: this.failures,
   462тЖТ      successes: this.successes,
   463тЖТ      lastFailureTime: this.lastFailureTime,
   464тЖТ      lastSuccessTime: this.lastSuccessTime,
   465тЖТ      totalRequests: this.totalRequests,
   466тЖТ      totalFailures: this.totalFailures,
   467тЖТ      totalSuccesses: this.totalSuccesses,
   468тЖТ    };
   469тЖТ  }
   470тЖТ
   471тЖТ  /**
   472тЖТ   * Get current state
   473тЖТ   */
   474тЖТ  getState(): CircuitState {
   475тЖТ    this.checkResetTimeout();
   476тЖТ    return this.state;
   477тЖТ  }
   478тЖТ
   479тЖТ  /**
   480тЖТ   * Manually reset the circuit breaker to CLOSED state
   481тЖТ   * Use with caution - primarily for testing or manual intervention
   482тЖТ   */
   483тЖТ  reset(): void {
   484тЖТ    this.log.warn('Circuit breaker manually reset');
   485тЖТ    this.state = 'CLOSED';
   486тЖТ    this.failures = 0;
   487тЖТ    this.successes = 0;
   488тЖТ  }
   489тЖТ
   490тЖТ  /**
   491тЖТ   * Manually open the circuit
   492тЖТ   * Use for graceful degradation scenarios
   493тЖТ   */
   494тЖТ  open(): void {
   495тЖТ    this.log.warn('Circuit breaker manually opened');
   496тЖТ    this.transition('OPEN');
   497тЖТ    this.lastFailureTime = new Date();
   498тЖТ  }
   499тЖТ}
   500тЖТ
   501тЖТ// =============================================================================
   502тЖТ// Combined Retry + Circuit Breaker
   503тЖТ// =============================================================================
   504тЖТ
   505тЖТ/**
   506тЖТ * Execute a function with both retry logic and circuit breaker protection
   507тЖТ *
   508тЖТ * The circuit breaker wraps the retry logic, so if the circuit is open,
   509тЖТ * no retries will be attempted.
   510тЖТ *
   511тЖТ * @example
   512тЖТ * ```typescript
   513тЖТ * const result = await withResilience(
   514тЖТ *   async () => fetchFromMaximo('/api/workorders'),
   515тЖТ *   maximoCircuitBreaker,
   516тЖТ *   EXTERNAL_SERVICE_RETRY_CONFIG,
   517тЖТ *   'fetchWorkOrders'
   518тЖТ * );
   519тЖТ * ```
   520тЖТ */
   521тЖТexport async function withResilience<T>(
   522тЖТ  fn: () => Promise<T>,
   523тЖТ  circuitBreaker: CircuitBreaker,
   524тЖТ  retryConfig?: Partial<RetryConfig>,
   525тЖТ  operationName?: string
   526тЖТ): Promise<T> {
   527тЖТ  return circuitBreaker.execute(async () => withRetry(fn, retryConfig, operationName));
   528тЖТ}
   529тЖТ
   530тЖТ// =============================================================================
   531тЖТ// Timeout Utility
   532тЖТ// =============================================================================
   533тЖТ
   534тЖТ/**
   535тЖТ * Execute a function with a timeout
   536тЖТ *
   537тЖТ * @example
   538тЖТ * ```typescript
   539тЖТ * const result = await withTimeout(
   540тЖТ *   async () => slowOperation(),
   541тЖТ *   5000,
   542тЖТ *   'slowOperation'
   543тЖТ * );
   544тЖТ * ```
   545тЖТ */
   546тЖТexport async function withTimeout<T>(
   547тЖТ  fn: () => Promise<T>,
   548тЖТ  timeoutMs: number,
   549тЖТ  operationName?: string
   550тЖТ): Promise<T> {
   551тЖТ  const name = operationName ?? 'operation';
   552тЖТ
   553тЖТ  return new Promise((resolve, reject) => {
   554тЖТ    const timer = setTimeout(() => {
   555тЖТ      reject(
   556тЖТ        new TimeoutError(`Operation ${name} timed out after ${timeoutMs}ms`, {
   557тЖТ          operation: name,
   558тЖТ          timeoutMs,
   559тЖТ        })
   560тЖТ      );
   561тЖТ    }, timeoutMs);
   562тЖТ
   563тЖТ    fn()
   564тЖТ      .then((result) => {
   565тЖТ        clearTimeout(timer);
   566тЖТ        resolve(result);
   567тЖТ      })
   568тЖТ      .catch((error) => {
   569тЖТ        clearTimeout(timer);
   570тЖТ        reject(error);
   571тЖТ      });
   572тЖТ  });
   573тЖТ}
   574тЖТ

