   279тЖТ      }
   280тЖТ    });
   281тЖТ  }
   282тЖТ
   283тЖТ  /**
   284тЖТ   * Fetch a work order from Maximo
   285тЖТ   *
   286тЖТ   * @param woNum Work order number
   287тЖТ   * @returns Work order data or null if not found
   288тЖТ   * @throws MaximoConnectionError if API call fails (except 404)
   289тЖТ   */
   290тЖТ  async getWorkOrder(woNum: string): Promise<MaximoWorkOrder | null> {
   291тЖТ    return withSpan('MaximoClient.getWorkOrder', async (span) => {
   292тЖТ      span.setAttribute('maximo.wo_num', woNum);
   293тЖТ
   294тЖТ      // Simulation mode
   295тЖТ      if (!this.config) {
   296тЖТ        log.debug({ woNum }, 'Fetching Maximo work order (simulated)');
   297тЖТ        await new Promise((resolve) => setTimeout(resolve, 50));
   298тЖТ        return {
   299тЖТ          wonum: woNum,
   300тЖТ          status: 'APPR' as MaximoWoStatus,
   301тЖТ          schedstart: new Date().toISOString(),
   302тЖТ          schedfinish: addDays(new Date(), 1).toISOString(),
   303тЖТ          changedate: new Date().toISOString(),
   304тЖТ        };
   305тЖТ      }
   306тЖТ
   307тЖТ      const url = `${this.config.baseUrl}/os/mxwo/${encodeURIComponent(woNum)}`;
   308тЖТ
   309тЖТ      try {
   310тЖТ        const response = await fetch(url, {
   311тЖТ          method: 'GET',
   312тЖТ          headers: this.buildHeaders(),
   313тЖТ          signal: AbortSignal.timeout(this.config.timeoutMs),
   314тЖТ        });
   315тЖТ
   316тЖТ        if (response.status === 404) {
   317тЖТ          return null;
   318тЖТ        }
   319тЖТ
   320тЖТ        if (!response.ok) {
   321тЖТ          const errorBody = await this.parseErrorResponse(response);
   322тЖТ          throw new MaximoConnectionError(
   323тЖТ            `Failed to fetch work order: ${errorBody}`,
   324тЖТ            { statusCode: response.status, url, woNum }
   325тЖТ          );
   326тЖТ        }
   327тЖТ
   328тЖТ        const data = await response.json();
   329тЖТ
   330тЖТ        return this.parseWorkOrderResponse(data);
   331тЖТ      } catch (error) {
   332тЖТ        if (error instanceof MaximoConnectionError) {
   333тЖТ          throw error;
   334тЖТ        }
   335тЖТ        throw new MaximoConnectionError(
   336тЖТ          `Failed to fetch work order: ${error instanceof Error ? error.message : String(error)}`,
   337тЖТ          { cause: error, woNum }
   338тЖТ        );
   339тЖТ      }
   340тЖТ    });
   341тЖТ  }
   342тЖТ
   343тЖТ  /**
   344тЖТ   * Update a work order in Maximo
   345тЖТ   *
   346тЖТ   * @param woNum Work order number
   347тЖТ   * @param payload Update payload
   348тЖТ   * @param options.force Force update even if Maximo has changes (conflict resolution)
   349тЖТ   * @throws MaximoConnectionError if API call fails
   350тЖТ   */
   351тЖТ  async updateWorkOrder(
   352тЖТ    woNum: string,
   353тЖТ    payload: MaximoWorkOrderUpdatePayload,
   354тЖТ    options?: { force?: boolean }
   355тЖТ  ): Promise<void> {
   356тЖТ    return withSpan('MaximoClient.updateWorkOrder', async (span) => {
   357тЖТ      span.setAttribute('maximo.wo_num', woNum);
   358тЖТ      span.setAttribute('force', options?.force ?? false);
   359тЖТ
   360тЖТ      // Simulation mode
   361тЖТ      if (!this.config) {
   362тЖТ        log.info({ woNum, payload, force: options?.force }, 'Updated Maximo work order (simulated)');
   363тЖТ        await new Promise((resolve) => setTimeout(resolve, 100));
   364тЖТ        return;
   365тЖТ      }
   366тЖТ
   367тЖТ      const url = `${this.config.baseUrl}/os/mxwo/${encodeURIComponent(woNum)}`;
   368тЖТ
   369тЖТ      try {
   370тЖТ        const headers = this.buildHeaders();
   371тЖТ
   372тЖТ        // Use PATCH method for partial updates, or POST with _action=Change
   373тЖТ        // Maximo OSLC supports both patterns
   374тЖТ        const response = await fetch(url, {
   375тЖТ          method: 'POST',
   376тЖТ          headers: {
   377тЖТ            ...headers,
   378тЖТ            'x-method-override': 'PATCH',
   379тЖТ            ...(options?.force ? { 'x-maximo-override': 'true' } : {}),
   380тЖТ          },
   381тЖТ          body: JSON.stringify(payload),
   382тЖТ          signal: AbortSignal.timeout(this.config.timeoutMs),
   383тЖТ        });
   384тЖТ
   385тЖТ        if (!response.ok) {
   386тЖТ          const errorBody = await this.parseErrorResponse(response);
   387тЖТ          throw new MaximoConnectionError(
   388тЖТ            `Failed to update work order: ${errorBody}`,
   389тЖТ            { statusCode: response.status, url, woNum }
   390тЖТ          );
   391тЖТ        }
   392тЖТ
   393тЖТ        log.info({ woNum, payload }, 'Updated Maximo work order');
   394тЖТ      } catch (error) {
   395тЖТ        if (error instanceof MaximoConnectionError) {
   396тЖТ          throw error;
   397тЖТ        }
   398тЖТ        throw new MaximoConnectionError(
   399тЖТ          `Failed to update work order: ${error instanceof Error ? error.message : String(error)}`,
   400тЖТ          { cause: error, woNum }
   401тЖТ        );
   402тЖТ      }
   403тЖТ    });
   404тЖТ  }
   405тЖТ
   406тЖТ  /**
   407тЖТ   * Query work orders modified since a given timestamp
   408тЖТ   *
   409тЖТ   * Used by pull sync to fetch status updates.
   410тЖТ   *
   411тЖТ   * @param since Fetch work orders modified after this time
   412тЖТ   * @param options.limit Maximum number of records to return
   413тЖТ   * @returns Array of work orders
   414тЖТ   */
   415тЖТ  async queryModifiedWorkOrders(
   416тЖТ    since: Date,
   417тЖТ    options?: { limit?: number }
   418тЖТ  ): Promise<MaximoWorkOrder[]> {
   419тЖТ    return withSpan('MaximoClient.queryModifiedWorkOrders', async (span) => {
   420тЖТ      const sinceStr = since.toISOString();
   421тЖТ      span.setAttribute('since', sinceStr);
   422тЖТ      span.setAttribute('limit', options?.limit ?? 100);
   423тЖТ
   424тЖТ      // Simulation mode
   425тЖТ      if (!this.config) {
   426тЖТ        log.debug({ since: sinceStr }, 'Querying modified work orders (simulated)');
   427тЖТ        await new Promise((resolve) => setTimeout(resolve, 50));
   428тЖТ        return [];
   429тЖТ      }
   430тЖТ
   431тЖТ      // Build OSLC query
   432тЖТ      // oslc.where=changedate>="2026-01-20T00:00:00Z"
   433тЖТ      const whereClause = encodeURIComponent(`changedate>="${sinceStr}"`);
   434тЖТ      const limit = options?.limit ?? 100;
   435тЖТ      const url = `${this.config.baseUrl}/os/mxwo?oslc.where=${whereClause}&oslc.pageSize=${limit}&oslc.select=wonum,status,schedstart,schedfinish,actstart,actfinish,actlabhrs,changedate`;
   436тЖТ
   437тЖТ      try {
   438тЖТ        const response = await fetch(url, {
   439тЖТ          method: 'GET',
   440тЖТ          headers: this.buildHeaders(),
   441тЖТ          signal: AbortSignal.timeout(this.config.timeoutMs),
   442тЖТ        });
   443тЖТ
   444тЖТ        if (!response.ok) {
   445тЖТ          const errorBody = await this.parseErrorResponse(response);
   446тЖТ          throw new MaximoConnectionError(
   447тЖТ            `Failed to query work orders: ${errorBody}`,
   448тЖТ            { statusCode: response.status, url }
   449тЖТ          );
   450тЖТ        }
   451тЖТ
   452тЖТ        const data = await response.json();
   453тЖТ
   454тЖТ        // Parse OSLC collection response
   455тЖТ        const members = data.member || data['rdfs:member'] || [];
   456тЖТ
   457тЖТ        return members.map((item: Record<string, unknown>) => this.parseWorkOrderResponse(item));
   458тЖТ      } catch (error) {
   459тЖТ        if (error instanceof MaximoConnectionError) {
   460тЖТ          throw error;
   461тЖТ        }
   462тЖТ        throw new MaximoConnectionError(
   463тЖТ          `Failed to query work orders: ${error instanceof Error ? error.message : String(error)}`,
   464тЖТ          { cause: error }
   465тЖТ        );
   466тЖТ      }
   467тЖТ    });
   468тЖТ  }
   469тЖТ
   470тЖТ  /**
   471тЖТ   * Test connection to Maximo API
   472тЖТ   *
   473тЖТ   * @returns true if connection successful
   474тЖТ   * @throws MaximoConnectionError if connection fails
   475тЖТ   */
   476тЖТ  async testConnection(): Promise<boolean> {
   477тЖТ    return withSpan('MaximoClient.testConnection', async (span) => {
   478тЖТ      if (!this.config) {
   479тЖТ        span.setAttribute('mode', 'simulation');
   480тЖТ        return true;
   481тЖТ      }
   482тЖТ
   483тЖТ      // Try to query a single work order to verify connectivity
   484тЖТ      const url = `${this.config.baseUrl}/os/mxwo?oslc.pageSize=1`;
   485тЖТ
   486тЖТ      try {
   487тЖТ        const response = await fetch(url, {
   488тЖТ          method: 'GET',
   489тЖТ          headers: this.buildHeaders(),
   490тЖТ          signal: AbortSignal.timeout(5000), // 5 second timeout for health check
   491тЖТ        });
   492тЖТ
   493тЖТ        if (!response.ok) {
   494тЖТ          throw new MaximoConnectionError(
   495тЖТ            `Connection test failed: HTTP ${response.status}`,
   496тЖТ            { statusCode: response.status }
   497тЖТ          );
   498тЖТ        }
   499тЖТ
   500тЖТ        span.setAttribute('status', 'connected');
   501тЖТ        return true;
   502тЖТ      } catch (error) {
   503тЖТ        span.setAttribute('status', 'failed');
   504тЖТ        span.setAttribute('error', error instanceof Error ? error.message : String(error));
   505тЖТ        throw new MaximoConnectionError(
   506тЖТ          `Connection test failed: ${error instanceof Error ? error.message : String(error)}`,
   507тЖТ          { cause: error }
   508тЖТ        );
   509тЖТ      }
   510тЖТ    });
   511тЖТ  }
   512тЖТ
   513тЖТ  // ===========================================================================
   514тЖТ  // Private Helper Methods
   515тЖТ  // ===========================================================================
   516тЖТ
   517тЖТ  private buildHeaders(): Record<string, string> {
   518тЖТ    if (!this.config) {
   519тЖТ      return { 'Content-Type': 'application/json' };
   520тЖТ    }
   521тЖТ
   522тЖТ    // Basic auth for Maximo OSLC API
   523тЖТ    const credentials = Buffer.from(`${this.config.username}:${this.config.password}`).toString('base64');
   524тЖТ
   525тЖТ    return {
   526тЖТ      'Content-Type': 'application/json',
   527тЖТ      'Accept': 'application/json',
   528тЖТ      'Authorization': `Basic ${credentials}`,
   529тЖТ      'x-public-uri': this.config.baseUrl,
   530тЖТ    };
   531тЖТ  }
   532тЖТ
   533тЖТ  private async parseErrorResponse(response: Response): Promise<string> {
   534тЖТ    try {
   535тЖТ      const text = await response.text();
   536тЖТ
   537тЖТ      // Try to parse as JSON
   538тЖТ      try {
   539тЖТ        const json = JSON.parse(text) as MaximoErrorResponse;
   540тЖТ        const message =
   541тЖТ          json.Error?.message ||
   542тЖТ          json.oslc?.Error?.['spi:message'] ||
   543тЖТ          `HTTP ${response.status}`;
   544тЖТ        return message;
   545тЖТ      } catch {
   546тЖТ        // Return raw text if not JSON
   547тЖТ        return text.substring(0, 500);
   548тЖТ      }
   549тЖТ    } catch {
   550тЖТ      return `HTTP ${response.status} ${response.statusText}`;
   551тЖТ    }
   552тЖТ  }
   553тЖТ
   554тЖТ  private parseWorkOrderResponse(data: Record<string, unknown>): MaximoWorkOrder {
   555тЖТ    // Handle both direct properties and spi: prefixed properties (Maximo OSLC format)
   556тЖТ    return {
   557тЖТ      wonum: (data.wonum || data['spi:wonum']) as string,
   558тЖТ      status: (data.status || data['spi:status'] || 'WAPPR') as MaximoWoStatus,
   559тЖТ      schedstart: (data.schedstart || data['spi:schedstart']) as string | undefined,
   560тЖТ      schedfinish: (data.schedfinish || data['spi:schedfinish']) as string | undefined,
   561тЖТ      actstart: (data.actstart || data['spi:actstart']) as string | undefined,
   562тЖТ      actfinish: (data.actfinish || data['spi:actfinish']) as string | undefined,
   563тЖТ      actlabhrs: (data.actlabhrs || data['spi:actlabhrs']) as number | undefined,
   564тЖТ      changedate: (data.changedate || data['spi:changedate']) as string | undefined,
   565тЖТ      description: (data.description || data['spi:description']) as string | undefined,
   566тЖТ      assetnum: (data.assetnum || data['spi:assetnum']) as string | undefined,
   567тЖТ      location: (data.location || data['spi:location']) as string | undefined,
   568тЖТ    };
   569тЖТ  }
   570тЖТ}
   571тЖТ
   572тЖТ// =============================================================================
   573тЖТ// Singleton Instance
   574тЖТ// =============================================================================
   575тЖТ
   576тЖТlet clientInstance: MaximoClient | null = null;
   577тЖТ
   578тЖТ/**
   579тЖТ * Get the singleton MaximoClient instance
   580тЖТ *
   581тЖТ * Call initialize() before using other methods.
   582тЖТ */
   583тЖТexport function getMaximoClient(): MaximoClient {
   584тЖТ  if (!clientInstance) {
   585тЖТ    clientInstance = new MaximoClient();
   586тЖТ  }
   587тЖТ  return clientInstance;
   588тЖТ}
   589тЖТ
   590тЖТ/**
   591тЖТ * Reset the client instance (for testing)
   592тЖТ */
   593тЖТexport function resetMaximoClient(): void {
   594тЖТ  clientInstance = null;
   595тЖТ}
