/**
 * MMS Maximo REST Client
 *
 * HTTP client for Maximo OSLC REST API integration.
 * Handles authentication, request/response serialization, and error handling.
 *
 * Configuration is loaded from `maximo_integration_config` table.
 * Password should be provided via environment variable `MAXIMO_API_PASSWORD`
 * or a secrets manager (not stored in database).
 *
 * @see specs/007-integration.md Section 7.4.3
 */

import { eq, and, isNull } from 'drizzle-orm';
import { addDays, format } from 'date-fns';
import { db } from '../lib/db/connection';
import { maximoIntegrationConfig } from '../lib/db/schema';
import { MaximoConnectionError } from '../lib/errors';
import logger from '../lib/logging/logger';
import { withSpan } from '../lib/tracing';

// =============================================================================
// Types
// =============================================================================

/** Maximo API configuration loaded from database */
export interface MaximoConfig {
  baseUrl: string;
  siteId: string;
  username: string;
  password: string;
  timeoutMs: number;
  maxRetries: number;
}

/** Maximo work order status values */
export type MaximoWoStatus = 'WAPPR' | 'APPR' | 'INPRG' | 'COMP' | 'CLOSE' | 'CAN';

/** Maximo work order create payload */
export interface MaximoWorkOrderCreatePayload {
  siteid: string;
  woclass: string;
  worktype: string;
  assetnum: string;
  description: string;
  schedstart: string;
  schedfinish: string;
  location?: string;
  estlabhrs?: number;
  pmnum?: string;
  mms_schedule_id: string;
  mms_constraint_start: string;
  mms_constraint_end: string;
}

/** Maximo work order update payload */
export interface MaximoWorkOrderUpdatePayload {
  schedstart?: string;
  schedfinish?: string;
  location?: string;
  estlabhrs?: number;
  description?: string;
}

/** Maximo work order response */
export interface MaximoWorkOrder {
  wonum: string;
  status: MaximoWoStatus;
  schedstart?: string;
  schedfinish?: string;
  actstart?: string;
  actfinish?: string;
  actlabhrs?: number;
  changedate?: string;
  description?: string;
  assetnum?: string;
  location?: string;
}

/** Maximo API error response */
export interface MaximoErrorResponse {
  Error?: {
    message?: string;
    reasonCode?: string;
    statusCode?: number;
  };
  oslc?: {
    Error?: {
      'spi:message'?: string;
      'spi:reasonCode'?: string;
    };
  };
}

// =============================================================================
// Logger
// =============================================================================

const log = logger.child({ service: 'MaximoClient' });

// =============================================================================
// MaximoClient Implementation
// =============================================================================

/**
 * HTTP client for Maximo OSLC REST API
 *
 * Implements the Maximo REST API calls defined in spec 007.4.3:
 * - GET /os/mxwo/{wonum} - Fetch WO details
 * - POST /os/mxwo - Create new WO
 * - POST /os/mxwo/{wonum} - Update WO
 *
 * @example
 * ```typescript
 * const client = new MaximoClient();
 * await client.initialize();
 *
 * // Create work order
 * const woNum = await client.createWorkOrder({
 *   siteid: 'METRO',
 *   woclass: 'WORKORDER',
 *   worktype: 'PM',
 *   assetnum: '1001',
 *   description: 'C2 - Brake Inspection',
 *   schedstart: '2026-02-15T08:00:00Z',
 *   schedfinish: '2026-02-15T17:00:00Z',
 *   mms_schedule_id: 'uuid-123',
 *   mms_constraint_start: '2026-02-10T00:00:00Z',
 *   mms_constraint_end: '2026-02-20T23:59:59Z',
 * });
 *
 * // Fetch work order
 * const wo = await client.getWorkOrder(woNum);
 *
 * // Update work order
 * await client.updateWorkOrder(woNum, { schedstart: '2026-02-16T08:00:00Z' });
 * ```
 */
export class MaximoClient {
  private config: MaximoConfig | null = null;
  private initialized = false;

  /**
   * Initialize the client by loading configuration from database
   *
   * @param depotId Optional depot ID for depot-specific config
   */
  async initialize(depotId?: string): Promise<void> {
    return withSpan('MaximoClient.initialize', async (span) => {
      if (depotId) {
        span.setAttribute('depot.id', depotId);
      }

      // db is imported from connection

      // Try to load depot-specific config first, then fall back to global
      let configRecord = depotId
        ? await db.query.maximoIntegrationConfig.findFirst({
            where: and(
              eq(maximoIntegrationConfig.depotId, depotId),
              eq(maximoIntegrationConfig.active, true)
            ),
          })
        : null;

      // Fall back to global config (depotId = NULL)
      if (!configRecord) {
        configRecord = await db.query.maximoIntegrationConfig.findFirst({
          where: and(
            isNull(maximoIntegrationConfig.depotId),
            eq(maximoIntegrationConfig.active, true)
          ),
        });
      }

      if (!configRecord) {
        log.warn({ depotId }, 'No Maximo integration config found, client will operate in simulation mode');
        this.initialized = true;
        return;
      }

      // Get password from environment variable
      const password = process.env['MAXIMO_API_PASSWORD'];
      if (!password) {
        log.warn('MAXIMO_API_PASSWORD not set, client will operate in simulation mode');
        this.initialized = true;
        return;
      }

      this.config = {
        baseUrl: configRecord.baseUrl,
        siteId: configRecord.siteId,
        username: configRecord.username,
        password,
        timeoutMs: (configRecord.circuitBreakerTimeout ?? 60000),
        maxRetries: configRecord.maxRetries ?? 5,
      };

      span.setAttribute('maximo.base_url', this.config.baseUrl);
      span.setAttribute('maximo.site_id', this.config.siteId);

      log.info(
        { baseUrl: this.config.baseUrl, siteId: this.config.siteId },
        'Maximo client initialized'
      );

      this.initialized = true;
    });
  }

  /**
   * Check if the client is configured for real API calls
   */
  isConfigured(): boolean {
    return this.config !== null;
  }

  /**
   * Create a work order in Maximo
   *
   * @param payload Work order create payload
   * @returns Created work order number
   * @throws MaximoConnectionError if API call fails
   */
  async createWorkOrder(payload: MaximoWorkOrderCreatePayload): Promise<string> {
    return withSpan('MaximoClient.createWorkOrder', async (span) => {
      span.setAttribute('maximo.asset', payload.assetnum);
      span.setAttribute('maximo.work_type', payload.worktype);
      span.setAttribute('mms.schedule_id', payload.mms_schedule_id);

      // Simulation mode
      if (!this.config) {
        const woNum = `WO-${format(new Date(), 'yyyy')}-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
        log.info({ woNum, payload }, 'Created Maximo work order (simulated)');
        await new Promise((resolve) => setTimeout(resolve, 100));
        return woNum;
      }

      const url = `${this.config.baseUrl}/os/mxwo`;

      try {
        const response = await fetch(url, {
          method: 'POST',
          headers: this.buildHeaders(),
          body: JSON.stringify(payload),
          signal: AbortSignal.timeout(this.config.timeoutMs),
        });

        if (!response.ok) {
          const errorBody = await this.parseErrorResponse(response);
          throw new MaximoConnectionError(
            `Failed to create work order: ${errorBody}`,
            { statusCode: response.status, url }
          );
        }

        const data = await response.json();
        const woNum = data.wonum || data._wonum || data['spi:wonum'];

        if (!woNum) {
          throw new MaximoConnectionError(
            'Work order created but wonum not returned',
            { response: data }
          );
        }

        span.setAttribute('maximo.wo_num', woNum);
        log.info({ woNum, assetnum: payload.assetnum }, 'Created Maximo work order');

        return woNum;
      } catch (error) {
        if (error instanceof MaximoConnectionError) {
          throw error;
        }
        throw new MaximoConnectionError(
          `Failed to create work order: ${error instanceof Error ? error.message : String(error)}`,
          { cause: error }
        );
      }
    });
  }

  /**
   * Fetch a work order from Maximo
   *
   * @param woNum Work order number
   * @returns Work order data or null if not found
   * @throws MaximoConnectionError if API call fails (except 404)
   */
  async getWorkOrder(woNum: string): Promise<MaximoWorkOrder | null> {
    return withSpan('MaximoClient.getWorkOrder', async (span) => {
      span.setAttribute('maximo.wo_num', woNum);

      // Simulation mode
      if (!this.config) {
        log.debug({ woNum }, 'Fetching Maximo work order (simulated)');
        await new Promise((resolve) => setTimeout(resolve, 50));
        return {
          wonum: woNum,
          status: 'APPR' as MaximoWoStatus,
          schedstart: new Date().toISOString(),
          schedfinish: addDays(new Date(), 1).toISOString(),
          changedate: new Date().toISOString(),
        };
      }

      const url = `${this.config.baseUrl}/os/mxwo/${encodeURIComponent(woNum)}`;

      try {
        const response = await fetch(url, {
          method: 'GET',
          headers: this.buildHeaders(),
          signal: AbortSignal.timeout(this.config.timeoutMs),
        });

        if (response.status === 404) {
          return null;
        }

        if (!response.ok) {
          const errorBody = await this.parseErrorResponse(response);
          throw new MaximoConnectionError(
            `Failed to fetch work order: ${errorBody}`,
            { statusCode: response.status, url, woNum }
          );
        }

        const data = await response.json();

        return this.parseWorkOrderResponse(data);
      } catch (error) {
        if (error instanceof MaximoConnectionError) {
          throw error;
        }
        throw new MaximoConnectionError(
          `Failed to fetch work order: ${error instanceof Error ? error.message : String(error)}`,
          { cause: error, woNum }
        );
      }
    });
  }

  /**
   * Update a work order in Maximo
   *
   * @param woNum Work order number
   * @param payload Update payload
   * @param options.force Force update even if Maximo has changes (conflict resolution)
   * @throws MaximoConnectionError if API call fails
   */
  async updateWorkOrder(
    woNum: string,
    payload: MaximoWorkOrderUpdatePayload,
    options?: { force?: boolean }
  ): Promise<void> {
    return withSpan('MaximoClient.updateWorkOrder', async (span) => {
      span.setAttribute('maximo.wo_num', woNum);
      span.setAttribute('force', options?.force ?? false);

      // Simulation mode
      if (!this.config) {
        log.info({ woNum, payload, force: options?.force }, 'Updated Maximo work order (simulated)');
        await new Promise((resolve) => setTimeout(resolve, 100));
        return;
      }

      const url = `${this.config.baseUrl}/os/mxwo/${encodeURIComponent(woNum)}`;

      try {
        const headers = this.buildHeaders();

        // Use PATCH method for partial updates, or POST with _action=Change
        // Maximo OSLC supports both patterns
        const response = await fetch(url, {
          method: 'POST',
          headers: {
            ...headers,
            'x-method-override': 'PATCH',
            ...(options?.force ? { 'x-maximo-override': 'true' } : {}),
          },
          body: JSON.stringify(payload),
          signal: AbortSignal.timeout(this.config.timeoutMs),
        });

        if (!response.ok) {
          const errorBody = await this.parseErrorResponse(response);
          throw new MaximoConnectionError(
            `Failed to update work order: ${errorBody}`,
            { statusCode: response.status, url, woNum }
          );
        }

        log.info({ woNum, payload }, 'Updated Maximo work order');
      } catch (error) {
        if (error instanceof MaximoConnectionError) {
          throw error;
        }
        throw new MaximoConnectionError(
          `Failed to update work order: ${error instanceof Error ? error.message : String(error)}`,
          { cause: error, woNum }
        );
      }
    });
  }

  /**
   * Query work orders modified since a given timestamp
   *
   * Used by pull sync to fetch status updates.
   *
   * @param since Fetch work orders modified after this time
   * @param options.limit Maximum number of records to return
   * @returns Array of work orders
   */
  async queryModifiedWorkOrders(
    since: Date,
    options?: { limit?: number }
  ): Promise<MaximoWorkOrder[]> {
    return withSpan('MaximoClient.queryModifiedWorkOrders', async (span) => {
      const sinceStr = since.toISOString();
      span.setAttribute('since', sinceStr);
      span.setAttribute('limit', options?.limit ?? 100);

      // Simulation mode
      if (!this.config) {
        log.debug({ since: sinceStr }, 'Querying modified work orders (simulated)');
        await new Promise((resolve) => setTimeout(resolve, 50));
        return [];
      }

      // Build OSLC query
      // oslc.where=changedate>="2026-01-20T00:00:00Z"
      const whereClause = encodeURIComponent(`changedate>="${sinceStr}"`);
      const limit = options?.limit ?? 100;
      const url = `${this.config.baseUrl}/os/mxwo?oslc.where=${whereClause}&oslc.pageSize=${limit}&oslc.select=wonum,status,schedstart,schedfinish,actstart,actfinish,actlabhrs,changedate`;

      try {
        const response = await fetch(url, {
          method: 'GET',
          headers: this.buildHeaders(),
          signal: AbortSignal.timeout(this.config.timeoutMs),
        });

        if (!response.ok) {
          const errorBody = await this.parseErrorResponse(response);
          throw new MaximoConnectionError(
            `Failed to query work orders: ${errorBody}`,
            { statusCode: response.status, url }
          );
        }

        const data = await response.json();

        // Parse OSLC collection response
        const members = data.member || data['rdfs:member'] || [];

        return members.map((item: Record<string, unknown>) => this.parseWorkOrderResponse(item));
      } catch (error) {
        if (error instanceof MaximoConnectionError) {
          throw error;
        }
        throw new MaximoConnectionError(
          `Failed to query work orders: ${error instanceof Error ? error.message : String(error)}`,
          { cause: error }
        );
      }
    });
  }

  /**
   * Test connection to Maximo API
   *
   * @returns true if connection successful
   * @throws MaximoConnectionError if connection fails
   */
  async testConnection(): Promise<boolean> {
    return withSpan('MaximoClient.testConnection', async (span) => {
      if (!this.config) {
        span.setAttribute('mode', 'simulation');
        return true;
      }

      // Try to query a single work order to verify connectivity
      const url = `${this.config.baseUrl}/os/mxwo?oslc.pageSize=1`;

      try {
        const response = await fetch(url, {
          method: 'GET',
          headers: this.buildHeaders(),
          signal: AbortSignal.timeout(5000), // 5 second timeout for health check
        });

        if (!response.ok) {
          throw new MaximoConnectionError(
            `Connection test failed: HTTP ${response.status}`,
            { statusCode: response.status }
          );
        }

        span.setAttribute('status', 'connected');
        return true;
      } catch (error) {
        span.setAttribute('status', 'failed');
        span.setAttribute('error', error instanceof Error ? error.message : String(error));
        throw new MaximoConnectionError(
          `Connection test failed: ${error instanceof Error ? error.message : String(error)}`,
          { cause: error }
        );
      }
    });
  }

  // ===========================================================================
  // Private Helper Methods
  // ===========================================================================

  private buildHeaders(): Record<string, string> {
    if (!this.config) {
      return { 'Content-Type': 'application/json' };
    }

    // Basic auth for Maximo OSLC API
    const credentials = Buffer.from(`${this.config.username}:${this.config.password}`).toString('base64');

    return {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'Authorization': `Basic ${credentials}`,
      'x-public-uri': this.config.baseUrl,
    };
  }

  private async parseErrorResponse(response: Response): Promise<string> {
    try {
      const text = await response.text();

      // Try to parse as JSON
      try {
        const json = JSON.parse(text) as MaximoErrorResponse;
        const message =
          json.Error?.message ||
          json.oslc?.Error?.['spi:message'] ||
          `HTTP ${response.status}`;
        return message;
      } catch {
        // Return raw text if not JSON
        return text.substring(0, 500);
      }
    } catch {
      return `HTTP ${response.status} ${response.statusText}`;
    }
  }

  private parseWorkOrderResponse(data: Record<string, unknown>): MaximoWorkOrder {
    // Handle both direct properties and spi: prefixed properties (Maximo OSLC format)
    return {
      wonum: (data.wonum || data['spi:wonum']) as string,
      status: (data.status || data['spi:status'] || 'WAPPR') as MaximoWoStatus,
      schedstart: (data.schedstart || data['spi:schedstart']) as string | undefined,
      schedfinish: (data.schedfinish || data['spi:schedfinish']) as string | undefined,
      actstart: (data.actstart || data['spi:actstart']) as string | undefined,
      actfinish: (data.actfinish || data['spi:actfinish']) as string | undefined,
      actlabhrs: (data.actlabhrs || data['spi:actlabhrs']) as number | undefined,
      changedate: (data.changedate || data['spi:changedate']) as string | undefined,
      description: (data.description || data['spi:description']) as string | undefined,
      assetnum: (data.assetnum || data['spi:assetnum']) as string | undefined,
      location: (data.location || data['spi:location']) as string | undefined,
    };
  }
}

// =============================================================================
// Singleton Instance
// =============================================================================

let clientInstance: MaximoClient | null = null;

/**
 * Get the singleton MaximoClient instance
 *
 * Call initialize() before using other methods.
 */
export function getMaximoClient(): MaximoClient {
  if (!clientInstance) {
    clientInstance = new MaximoClient();
  }
  return clientInstance;
}

/**
 * Reset the client instance (for testing)
 */
export function resetMaximoClient(): void {
  clientInstance = null;
}

