    78тЖТ/**
    79тЖТ * Maximo Webhook Payload
    80тЖТ *
    81тЖТ * Payload sent by Maximo when a work order status changes.
    82тЖТ */
    83тЖТinterface MaximoWebhookPayload {
    84тЖТ  /** Event type */
    85тЖТ  event: MaximoWebhookEventType;
    86тЖТ  /** Work order number (e.g., "WO-2026-ABC123") */
    87тЖТ  wonum: string;
