   109тЖТfunction validateWebhookPayload(
   110тЖТ  payload: unknown
   111тЖТ): { valid: true; data: MaximoWebhookPayload } | { valid: false; error: string } {
   112тЖТ  if (typeof payload !== 'object' || payload === null) {
