   114тЖТ  }
   115тЖТ
   116тЖТ  const p = payload as Record<string, unknown>;
   117тЖТ
   118тЖТ  // Required: event
   119тЖТ  if (!p.event || typeof p.event !== 'string') {
   120тЖТ    return { valid: false, error: 'Missing or invalid event field' };
   121тЖТ  }
   122тЖТ
   123тЖТ  const validEvents: MaximoWebhookEventType[] = [
   124тЖТ    'wo_status_changed',
   125тЖТ    'wo_created',
   126тЖТ    'wo_updated',
   127тЖТ    'wo_cancelled',
   128тЖТ  ];
   129тЖТ  if (!validEvents.includes(p.event as MaximoWebhookEventType)) {
   130тЖТ    return { valid: false, error: `Invalid event type: ${p.event}` };
   131тЖТ  }
   132тЖТ
   133тЖТ  // Required: wonum
   134тЖТ  if (!p.wonum || typeof p.wonum !== 'string') {
   135тЖТ    return { valid: false, error: 'Missing or invalid wonum field' };
