   141тЖТ  }
   142тЖТ
   143тЖТ  // Validate changedate is valid ISO 8601
   144тЖТ  const changeDate = new Date(p.changedate);
   145тЖТ  if (isNaN(changeDate.getTime())) {
   146тЖТ    return { valid: false, error: 'changedate must be valid ISO 8601 format' };
   147тЖТ  }
   148тЖТ
   149тЖТ  // Optional: status (required for wo_status_changed)
   150тЖТ  if (p.event === 'wo_status_changed') {
   151тЖТ    if (!p.status || typeof p.status !== 'string') {
   152тЖТ      return { valid: false, error: 'status is required for wo_status_changed event' };
   153тЖТ    }
   154тЖТ
   155тЖТ    const validStatuses: MaximoWoStatus[] = ['WAPPR', 'APPR', 'INPRG', 'COMP', 'CLOSE', 'CAN'];
   156тЖТ    if (!validStatuses.includes(p.status as MaximoWoStatus)) {
