   293тЖТ
   294тЖТ        // Update shadow record with new Maximo data
   295тЖТ        await db
   296тЖТ          .update(maximoShadowRecords)
   297тЖТ          .set({
   298тЖТ            maximoData: {
   299тЖТ              status: payload.status,
   300тЖТ              actualStart: payload.actstart,
   301тЖТ              actualFinish: payload.actfinish,
