   309тЖТ          .where(eq(maximoShadowRecords.id, currentShadow.id));
   310тЖТ
   311тЖТ        // Map Maximo status to MMS status
   312тЖТ        const mmsStatus = MAXIMO_TO_MMS_STATUS[payload.status];
   313тЖТ
