   327тЖТ              isLocked: isLocked,
   328тЖТ              actualStartDate: payload.actstart ? payload.actstart.split('T')[0] : pmRecord.actualStartDate,
   329тЖТ              actualEndDate: payload.actfinish ? payload.actfinish.split('T')[0] : pmRecord.actualEndDate,
   330тЖТ              actualHours: payload.actlabhrs !== undefined
   331тЖТ                ? payload.actlabhrs.toString()
   332тЖТ                : pmRecord.actualHours,
   333тЖТ              updatedAt: new Date(),
   334тЖТ            })
   335тЖТ            .where(eq(pmSchedule.id, pmRecord.id));
   336тЖТ
   337тЖТ          mmsStatusUpdated = true;
   338тЖТ          pmLocked = isLocked;
   339тЖТ
   340тЖТ          logger.info(
   341тЖТ            {
   342тЖТ              requestId,
   343тЖТ              pmScheduleId: pmRecord.id,
   344тЖТ              previousStatus,
   345тЖТ              newStatus: payload.status,
   346тЖТ              mmsStatus,
   347тЖТ              isLocked,
   348тЖТ            },
   349тЖТ            'Updated PM schedule from Maximo webhook'
   350тЖТ          );
   351тЖТ        }
   352тЖТ
   353тЖТ        action = 'status_updated';
   354тЖТ      }
   355тЖТ    } else if (payload.event === 'wo_cancelled') {
   356тЖТ      // Handle work order cancellation
   357тЖТ      const currentShadow = await db.query.maximoShadowRecords.findFirst({
   358тЖТ        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
   359тЖТ      });
   360тЖТ
   361тЖТ      if (currentShadow) {
   362тЖТ        await db
   363тЖТ          .update(maximoShadowRecords)
   364тЖТ          .set({
   365тЖТ            maximoData: {
   366тЖТ              status: 'CAN',
   367тЖТ              changeDate: payload.changedate,
   368тЖТ            },
   369тЖТ            syncStatus: 'SYNCED',
   370тЖТ            updatedAt: new Date(),
   371тЖТ          })
   372тЖТ          .where(eq(maximoShadowRecords.id, currentShadow.id));
   373тЖТ
   374тЖТ        // Update PM schedule to CANCELLED and locked
   375тЖТ        await db
   376тЖТ          .update(pmSchedule)
   377тЖТ          .set({
   378тЖТ            status: 'CANCELLED',
   379тЖТ            isLocked: true,
   380тЖТ            updatedAt: new Date(),
   381тЖТ          })
   382тЖТ          .where(eq(pmSchedule.id, currentShadow.pmScheduleId));
   383тЖТ
   384тЖТ        action = 'wo_cancelled';
   385тЖТ        mmsStatusUpdated = true;
   386тЖТ        pmLocked = true;
   387тЖТ
   388тЖТ        logger.info(
   389тЖТ          { requestId, pmScheduleId: currentShadow.pmScheduleId, wonum: payload.wonum },
   390тЖТ          'PM cancelled from Maximo webhook'
   391тЖТ        );
   392тЖТ      }
   393тЖТ    }
   394тЖТ
   395тЖТ    const durationMs = Date.now() - startTime;
   396тЖТ
   397тЖТ    return c.json(
   398тЖТ      success({
   399тЖТ        received: true,
   400тЖТ        processed: true,
   401тЖТ        action,
   402тЖТ        wonum: payload.wonum,
   403тЖТ        event: payload.event,
   404тЖТ        mmsStatusUpdated,
   405тЖТ        pmLocked,
   406тЖТ        durationMs,
   407тЖТ      }),
   408тЖТ      200
   409тЖТ    );
   410тЖТ  } catch (err) {
   411тЖТ    logger.error({ requestId, error: err, wonum: payload.wonum }, 'Failed to process Maximo webhook');
   412тЖТ    return c.json(
   413тЖТ      error(
   414тЖТ        ErrorCodes.INTERNAL_ERROR,
   415тЖТ        'Failed to process webhook',
   416тЖТ        requestId,
   417тЖТ        { wonum: payload.wonum }
   418тЖТ      ),
   419тЖТ      500
   420тЖТ    );
   421тЖТ  }
   422тЖТ});
