   775тЖТ          actualStart: maximoData.actualStart,
   776тЖТ          actualFinish: maximoData.actualFinish,
   777тЖТ          actualLabor: maximoData.actualLabor,
   778тЖТ          changeDate: maximoData.changeDate,
   779тЖТ        } : null,
   780тЖТ        pmSchedule: {
   781тЖТ          id: shadowRecord.pmScheduleEntry.id,
   782тЖТ          trainId: shadowRecord.pmScheduleEntry.trainId,
   783тЖТ          trainNumber: shadowRecord.pmScheduleEntry.train?.trainNumber,
   784тЖТ          pmTypeCode: shadowRecord.pmScheduleEntry.pmType?.pmCode,
   785тЖТ          pmTypeName: shadowRecord.pmScheduleEntry.pmType?.pmName,
   786тЖТ          targetDate: shadowRecord.pmScheduleEntry.targetDate,
   787тЖТ          currentStatus: shadowRecord.pmScheduleEntry.status,
   788тЖТ          depotCode: shadowRecord.pmScheduleEntry.assignedDepot?.code,
   789тЖТ        },
   790тЖТ        resolutionOptions: [
   791тЖТ          {
   792тЖТ            strategy: 'USE_MMS',
   793тЖТ            description: 'Overwrite Maximo with MMS data (force push)',
   794тЖТ          },
   795тЖТ          {
   796тЖТ            strategy: 'USE_MAXIMO',
