   801тЖТ        updatedAt: shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
   802тЖТ      }, { timing: { durationMs: getRequestDuration(c) } })
   803тЖТ    );
   804тЖТ  } catch (err) {
   805тЖТ    logger.error({ requestId, error: err }, 'Failed to get conflict details');
   806тЖТ    return c.json(
   807тЖТ      error(ErrorCodes.INTERNAL_ERROR, 'Failed to get conflict details', requestId),
   808тЖТ      500
