   813тЖТ/**
   814тЖТ * Conflict resolution request body
   815тЖТ */
   816тЖТinterface ResolveConflictRequest {
   817тЖТ  /** Resolution strategy: USE_MMS or USE_MAXIMO */
   818тЖТ  resolution: ConflictResolution;
   819тЖТ}
   820тЖТ
   821тЖТ/**
   822тЖТ * POST /integration/conflicts/:id/resolve
   823тЖТ *
   824тЖТ * Resolve a sync conflict.
   825тЖТ *
   826тЖТ * @param id - PM schedule ID (not shadow record ID)
   827тЖТ * @body resolution - Strategy: "USE_MMS" or "USE_MAXIMO"
   828тЖТ *
   829тЖТ * - USE_MMS: Force push MMS data to Maximo (overwrite)
   830тЖТ * - USE_MAXIMO: Apply Maximo data to MMS (accept Maximo's truth)
   831тЖТ */
   832тЖТintegrationRoutes.post('/integration/conflicts/:id/resolve', async (c) => {
   833тЖТ  const requestId = getRequestId(c);
   834тЖТ  const id = c.req.param('id');
   835тЖТ  const service = getService();
   836тЖТ
   837тЖТ  if (!isValidUuid(id)) {
   838тЖТ    return c.json(
   839тЖТ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
   840тЖТ      400
   841тЖТ    );
   842тЖТ  }
   843тЖТ
   844тЖТ  let body: ResolveConflictRequest;
   845тЖТ
   846тЖТ  try {
   847тЖТ    body = await c.req.json();
   848тЖТ  } catch {
   849тЖТ    return c.json(
   850тЖТ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   851тЖТ      400
   852тЖТ    );
   853тЖТ  }
   854тЖТ
   855тЖТ  // Validate resolution
   856тЖТ  if (!body.resolution || !['USE_MMS', 'USE_MAXIMO'].includes(body.resolution)) {
   857тЖТ    return c.json(
   858тЖТ      error(
   859тЖТ        ErrorCodes.VALIDATION_ERROR,
   860тЖТ        'resolution must be "USE_MMS" or "USE_MAXIMO"',
   861тЖТ        requestId
   862тЖТ      ),
   863тЖТ      400
   864тЖТ    );
   865тЖТ  }
   866тЖТ
   867тЖТ  // First, check if this is a shadow record ID or PM schedule ID
   868тЖТ  // Using imported db singleton
   869тЖТ  let pmScheduleId = id;
   870тЖТ
   871тЖТ  // Try to find shadow record by ID first
   872тЖТ  const shadowById = await db.query.maximoShadowRecords.findFirst({
   873тЖТ    where: eq(maximoShadowRecords.id, id),
   874тЖТ  });
   875тЖТ
   876тЖТ  if (shadowById) {
   877тЖТ    pmScheduleId = shadowById.pmScheduleId;
   878тЖТ  }
   879тЖТ
   880тЖТ  try {
   881тЖТ    // Get user ID from context if available (for audit)
   882тЖТ    const user = c.get('user');
   883тЖТ    const userId = user?.id;
   884тЖТ
   885тЖТ    await service.resolveConflict(pmScheduleId, body.resolution, userId);
   886тЖТ
   887тЖТ    logger.info(
   888тЖТ      { requestId, pmScheduleId, resolution: body.resolution, userId },
   889тЖТ      'Conflict resolved'
   890тЖТ    );
   891тЖТ
   892тЖТ    return c.json(
   893тЖТ      success({
   894тЖТ        resolved: true,
   895тЖТ        pmScheduleId,
   896тЖТ        resolution: body.resolution,
   897тЖТ        message:
   898тЖТ          body.resolution === 'USE_MMS'
   899тЖТ            ? 'MMS data pushed to Maximo'
   900тЖТ            : 'Maximo data applied to MMS',
   901тЖТ      }, { timing: { durationMs: getRequestDuration(c) } })
   902тЖТ    );
   903тЖТ  } catch (err) {
   904тЖТ    if (err instanceof NotFoundError) {
   905тЖТ      return c.json(
   906тЖТ        error(ErrorCodes.NOT_FOUND, err.message, requestId),
   907тЖТ        404
   908тЖТ      );
   909тЖТ    }
   910тЖТ
   911тЖТ    if (err instanceof ValidationError) {
   912тЖТ      return c.json(
   913тЖТ        error(ErrorCodes.VALIDATION_ERROR, err.message, requestId),
   914тЖТ        400
   915тЖТ      );
   916тЖТ    }
   917тЖТ
   918тЖТ    logger.error({ requestId, pmScheduleId, error: err }, 'Failed to resolve conflict');
   919тЖТ    return c.json(
   920тЖТ      error(ErrorCodes.INTERNAL_ERROR, 'Failed to resolve conflict', requestId),
   921тЖТ      500
   922тЖТ    );
   923тЖТ  }
   924тЖТ});
