   930тЖТ/**
   931тЖТ * GET /integration/shadow-records
   932тЖТ *
   933тЖТ * List shadow records with filtering.
   934тЖТ *
   935тЖТ * Query Parameters:
   936тЖТ * - syncStatus: Filter by status (PENDING, SYNCED, CONFLICT, ERROR)
   937тЖТ * - pmScheduleId: Filter by PM schedule ID
   938тЖТ * - maximoWoNum: Filter by Maximo WO number
   939тЖТ * - needsSync: Only show records needing sync (boolean)
   940тЖТ * - page: Page number (default: 1)
   941тЖТ * - pageSize: Items per page (default: 50, max: 200)
   942тЖТ *
   943тЖТ * @returns Paginated list of shadow records
   944тЖТ */
   945тЖТintegrationRoutes.get('/integration/shadow-records', async (c) => {
   946тЖТ  const requestId = getRequestId(c);
   947тЖТ  const service = getService();
   948тЖТ
   949тЖТ  // Parse query parameters
   950тЖТ  const syncStatus = c.req.query('syncStatus');
   951тЖТ  const pmScheduleId = c.req.query('pmScheduleId');
   952тЖТ  const maximoWoNum = c.req.query('maximoWoNum');
   953тЖТ  const needsSyncParam = c.req.query('needsSync');
   954тЖТ
   955тЖТ  // Validate pmScheduleId if provided
   956тЖТ  if (pmScheduleId && !isValidUuid(pmScheduleId)) {
   957тЖТ    return c.json(
   958тЖТ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid pmScheduleId format', requestId),
   959тЖТ      400
   960тЖТ    );
   961тЖТ  }
   962тЖТ
   963тЖТ  // Validate syncStatus if provided
   964тЖТ  const validStatuses = ['PENDING', 'SYNCED', 'CONFLICT', 'ERROR'];
   965тЖТ  if (syncStatus && !validStatuses.includes(syncStatus)) {
   966тЖТ    return c.json(
   967тЖТ      error(
   968тЖТ        ErrorCodes.VALIDATION_ERROR,
   969тЖТ        `Invalid syncStatus. Must be one of: ${validStatuses.join(', ')}`,
   970тЖТ        requestId
   971тЖТ      ),
   972тЖТ      400
   973тЖТ    );
   974тЖТ  }
   975тЖТ
   976тЖТ  const pagination = parsePaginationQuery({
   977тЖТ    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   978тЖТ    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   979тЖТ  });
   980тЖТ
   981тЖТ  try {
   982тЖТ    const result = await service.listShadowRecords(
   983тЖТ      {
   984тЖТ        syncStatus: syncStatus as 'PENDING' | 'SYNCED' | 'CONFLICT' | 'ERROR' | undefined,
   985тЖТ        pmScheduleId: pmScheduleId || undefined,
   986тЖТ        maximoWoNum: maximoWoNum || undefined,
   987тЖТ        needsSync: needsSyncParam === 'true',
   988тЖТ      },
   989тЖТ      { page: pagination.page, pageSize: pagination.pageSize }
   990тЖТ    );
   991тЖТ
   992тЖТ    // Transform to API response format
   993тЖТ    const records = result.data.map((item) => ({
   994тЖТ      id: item.shadowRecord.id,
   995тЖТ      pmScheduleId: item.shadowRecord.pmScheduleId,
   996тЖТ      maximoWoNum: item.shadowRecord.maximoWoNum,
   997тЖТ      maximoWoId: item.shadowRecord.maximoWoId,
   998тЖТ      syncStatus: item.shadowRecord.syncStatus,
   999тЖТ      syncAttempts: item.shadowRecord.syncAttempts,
  1000тЖТ      lastSyncAt: item.shadowRecord.lastSyncAt?.toISOString() ?? null,
  1001тЖТ      lastSyncError: item.shadowRecord.lastSyncError,
  1002тЖТ      nextSyncAt: item.shadowRecord.nextSyncAt?.toISOString() ?? null,
  1003тЖТ      pmSchedule: {
  1004тЖТ        id: item.pmSchedule.id,
  1005тЖТ        trainNumber: item.pmSchedule.train?.trainNumber,
  1006тЖТ        pmTypeCode: item.pmSchedule.pmType?.pmCode,
  1007тЖТ        targetDate: item.pmSchedule.targetDate,
  1008тЖТ        status: item.pmSchedule.status,
  1009тЖТ        depotCode: item.pmSchedule.depot?.code,
  1010тЖТ      },
  1011тЖТ      createdAt: item.shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
  1012тЖТ      updatedAt: item.shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
  1013тЖТ    }));
  1014тЖТ
  1015тЖТ    return c.json(
  1016тЖТ      paginatedSuccess(records, {
  1017тЖТ        page: result.page,
  1018тЖТ        pageSize: result.pageSize,
  1019тЖТ        totalItems: result.total,
  1020тЖТ      }, { durationMs: getRequestDuration(c) })
  1021тЖТ    );
  1022тЖТ  } catch (err) {
  1023тЖТ    logger.error({ requestId, error: err }, 'Failed to list shadow records');
  1024тЖТ    return c.json(
  1025тЖТ      error(ErrorCodes.INTERNAL_ERROR, 'Failed to list shadow records', requestId),
  1026тЖТ      500
  1027тЖТ    );
  1028тЖТ  }
  1029тЖТ});
