  1159тЖТ
  1160тЖТ/**
  1161тЖТ * POST /integration/validate-edit
  1162тЖТ *
  1163тЖТ * Validate if a PM can be edited (not locked by Maximo).
  1164тЖТ *
  1165тЖТ * This should be called before any PM modification operation to check:
  1166тЖТ * 1. Maximo status lock (INPRG, COMP, CLOSE, CAN тЖТ read-only)
  1167тЖТ * 2. Sync conflict (unresolved conflict тЖТ must resolve first)
  1168тЖТ * 3. Baseline lock (locked in published baseline тЖТ needs scenario)
  1169тЖТ *
  1170тЖТ * @body pmScheduleId - PM schedule ID to validate
  1171тЖТ * @returns Validation result with reason if invalid
  1172тЖТ */
  1173тЖТintegrationRoutes.post('/integration/validate-edit', async (c) => {
  1174тЖТ  const requestId = getRequestId(c);
  1175тЖТ  const service = getService();
  1176тЖТ
  1177тЖТ  let body: { pmScheduleId: string };
  1178тЖТ
  1179тЖТ  try {
  1180тЖТ    body = await c.req.json();
  1181тЖТ  } catch {
  1182тЖТ    return c.json(
  1183тЖТ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
  1184тЖТ      400
  1185тЖТ    );
  1186тЖТ  }
  1187тЖТ
  1188тЖТ  if (!body.pmScheduleId || !isValidUuid(body.pmScheduleId)) {
  1189тЖТ    return c.json(
  1190тЖТ      error(ErrorCodes.VALIDATION_ERROR, 'Invalid or missing pmScheduleId', requestId),
  1191тЖТ      400
  1192тЖТ    );
  1193тЖТ  }
  1194тЖТ
  1195тЖТ  try {
  1196тЖТ    const validation = await service.validateEdit(body.pmScheduleId);
  1197тЖТ
  1198тЖТ    if (!validation.valid) {
  1199тЖТ      // Return 423 Locked for Maximo status lock
  1200тЖТ      if (validation.reason === 'MAXIMO_STATUS_LOCK') {
  1201тЖТ        return c.json(
  1202тЖТ          error(
  1203тЖТ            ErrorCodes.MAXIMO_LOCK,
  1204тЖТ            validation.message ?? 'PM is locked by Maximo',
  1205тЖТ            requestId,
  1206тЖТ            {
  1207тЖТ              reason: validation.reason,
  1208тЖТ              maximoStatus: validation.maximoStatus,
  1209тЖТ              maximoWoNum: validation.maximoWoNum,
  1210тЖТ              suggestion: validation.suggestion,
  1211тЖТ            }
  1212тЖТ          ),
  1213тЖТ          423
  1214тЖТ        );
  1215тЖТ      }
  1216тЖТ
  1217тЖТ      // Return 409 Conflict for sync conflict
  1218тЖТ      if (validation.reason === 'SYNC_CONFLICT') {
  1219тЖТ        return c.json(
  1220тЖТ          error(
  1221тЖТ            ErrorCodes.CONFLICT,
  1222тЖТ            validation.message ?? 'Unresolved sync conflict',
  1223тЖТ            requestId,
  1224тЖТ            {
  1225тЖТ              reason: validation.reason,
  1226тЖТ              suggestion: validation.suggestion,
  1227тЖТ            }
  1228тЖТ          ),
  1229тЖТ          409
  1230тЖТ        );
  1231тЖТ      }
  1232тЖТ
  1233тЖТ      // Return 423 for baseline lock
  1234тЖТ      if (validation.reason === 'BASELINE_LOCK') {
  1235тЖТ        return c.json(
  1236тЖТ          error(
  1237тЖТ            ErrorCodes.BASELINE_LOCK,
  1238тЖТ            validation.message ?? 'PM is locked in published baseline',
  1239тЖТ            requestId,
  1240тЖТ            {
  1241тЖТ              reason: validation.reason,
  1242тЖТ              suggestion: validation.suggestion,
  1243тЖТ            }
  1244тЖТ          ),
  1245тЖТ          423
  1246тЖТ        );
  1247тЖТ      }
  1248тЖТ
  1249тЖТ      // Return 404 for not found
  1250тЖТ      return c.json(
  1251тЖТ        error(ErrorCodes.NOT_FOUND, validation.message ?? 'PM not found', requestId),
  1252тЖТ        404
  1253тЖТ      );
  1254тЖТ    }
  1255тЖТ
  1256тЖТ    return c.json(
  1257тЖТ      success({
  1258тЖТ        valid: true,
  1259тЖТ        pmScheduleId: body.pmScheduleId,
  1260тЖТ        message: 'PM can be edited',
  1261тЖТ      }, { timing: { durationMs: getRequestDuration(c) } })
  1262тЖТ    );
  1263тЖТ  } catch (err) {
  1264тЖТ    logger.error({ requestId, error: err }, 'Failed to validate edit');
  1265тЖТ    return c.json(
  1266тЖТ      error(ErrorCodes.INTERNAL_ERROR, 'Failed to validate edit', requestId),
  1267тЖТ      500
  1268тЖТ    );
  1269тЖТ  }
  1270тЖТ});
