/**
 * Integration Routes
 *
 * REST endpoints for Maximo integration, including:
 * - Webhook receiver for CM status updates from Maximo
 * - Sync operations (push, pull, full)
 * - Conflict management
 * - Sync statistics
 *
 * Integration flow:
 * 1. Maximo sends webhook on WO status change тЖТ POST /integration/webhooks/maximo
 * 2. MMS updates shadow record and PM status
 * 3. For proactive sync: POST /integration/sync/pull
 * 4. Conflicts are resolved via POST /integration/conflicts/:id/resolve
 *
 * @see specs/007-integration.md
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  ErrorCodes,
  parsePaginationQuery,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getMaximoSyncService,
  getMaximoPollingService,
  type ConflictResolution,
  type MaximoWoStatus,
  MAXIMO_TO_MMS_STATUS,
  MAXIMO_STATUS_LABELS,
  LOCKED_MAXIMO_STATUSES,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';
import { NotFoundError, ValidationError } from '../../lib/errors';
import { logger } from '../../lib/logging/logger';
import { eq } from 'drizzle-orm';
import { maximoShadowRecords, pmSchedule } from '../../lib/db/schema';
import { db } from '../../lib/db/connection';

// Singleton service instances
let maximoSyncService: ReturnType<typeof getMaximoSyncService> | null = null;
let maximoPollingService: ReturnType<typeof getMaximoPollingService> | null = null;

function getService(): ReturnType<typeof getMaximoSyncService> {
  if (!maximoSyncService) {
    maximoSyncService = getMaximoSyncService();
  }
  return maximoSyncService;
}

function getPollingService(): ReturnType<typeof getMaximoPollingService> {
  if (!maximoPollingService) {
    maximoPollingService = getMaximoPollingService();
  }
  return maximoPollingService;
}

export const integrationRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Webhook Endpoints
// =============================================================================

/**
 * Maximo Webhook Event Types
 */
type MaximoWebhookEventType =
  | 'wo_status_changed'
  | 'wo_created'
  | 'wo_updated'
  | 'wo_cancelled';

/**
 * Maximo Webhook Payload
 *
 * Payload sent by Maximo when a work order status changes.
 */
interface MaximoWebhookPayload {
  /** Event type */
  event: MaximoWebhookEventType;
  /** Work order number (e.g., "WO-2026-ABC123") */
  wonum: string;
  /** New status (e.g., "INPRG", "COMP") */
  status?: MaximoWoStatus;
  /** Timestamp of the change (ISO 8601) */
  changedate: string;
  /** Optional: Site ID */
  siteid?: string;
  /** Optional: Asset number (train number) */
  assetnum?: string;
  /** Optional: Actual start date */
  actstart?: string;
  /** Optional: Actual finish date */
  actfinish?: string;
  /** Optional: Actual labor hours */
  actlabhrs?: number;
  /** Optional: MMS schedule ID backreference */
  mms_schedule_id?: string;
}

/**
 * Validate Maximo webhook payload
 */
function validateWebhookPayload(
  payload: unknown
): { valid: true; data: MaximoWebhookPayload } | { valid: false; error: string } {
  if (typeof payload !== 'object' || payload === null) {
    return { valid: false, error: 'Payload must be an object' };
  }

  const p = payload as Record<string, unknown>;

  // Required: event
  if (!p.event || typeof p.event !== 'string') {
    return { valid: false, error: 'Missing or invalid event field' };
  }

  const validEvents: MaximoWebhookEventType[] = [
    'wo_status_changed',
    'wo_created',
    'wo_updated',
    'wo_cancelled',
  ];
  if (!validEvents.includes(p.event as MaximoWebhookEventType)) {
    return { valid: false, error: `Invalid event type: ${p.event}` };
  }

  // Required: wonum
  if (!p.wonum || typeof p.wonum !== 'string') {
    return { valid: false, error: 'Missing or invalid wonum field' };
  }

  // Required: changedate
  if (!p.changedate || typeof p.changedate !== 'string') {
    return { valid: false, error: 'Missing or invalid changedate field' };
  }

  // Validate changedate is valid ISO 8601
  const changeDate = new Date(p.changedate);
  if (isNaN(changeDate.getTime())) {
    return { valid: false, error: 'changedate must be valid ISO 8601 format' };
  }

  // Optional: status (required for wo_status_changed)
  if (p.event === 'wo_status_changed') {
    if (!p.status || typeof p.status !== 'string') {
      return { valid: false, error: 'status is required for wo_status_changed event' };
    }

    const validStatuses: MaximoWoStatus[] = ['WAPPR', 'APPR', 'INPRG', 'COMP', 'CLOSE', 'CAN'];
    if (!validStatuses.includes(p.status as MaximoWoStatus)) {
      return { valid: false, error: `Invalid status: ${p.status}` };
    }
  }

  return {
    valid: true,
    data: {
      event: p.event as MaximoWebhookEventType,
      wonum: p.wonum as string,
      status: p.status as MaximoWoStatus | undefined,
      changedate: p.changedate as string,
      siteid: typeof p.siteid === 'string' ? p.siteid : undefined,
      assetnum: typeof p.assetnum === 'string' ? p.assetnum : undefined,
      actstart: typeof p.actstart === 'string' ? p.actstart : undefined,
      actfinish: typeof p.actfinish === 'string' ? p.actfinish : undefined,
      actlabhrs: typeof p.actlabhrs === 'number' ? p.actlabhrs : undefined,
      mms_schedule_id: typeof p.mms_schedule_id === 'string' ? p.mms_schedule_id : undefined,
    },
  };
}

/**
 * POST /integration/webhooks/maximo
 *
 * Receive CM/WO status updates from Maximo.
 *
 * This endpoint is called by Maximo when:
 * - Work order status changes (WAPPR тЖТ APPR тЖТ INPRG тЖТ COMP тЖТ CLOSE)
 * - Work order is cancelled (CAN)
 * - Actual labor hours are recorded
 *
 * The webhook updates the shadow record and locks the PM if necessary.
 *
 * @security This endpoint should be protected by Maximo webhook authentication
 * (e.g., shared secret, IP allowlist, or mutual TLS)
 *
 * @see specs/007-integration.md Section 7.4.7
 */
integrationRoutes.post('/integration/webhooks/maximo', async (c) => {
  const requestId = getRequestId(c);
  const startTime = Date.now();

  let payload: MaximoWebhookPayload;

  try {
    const body = await c.req.json();
    const validation = validateWebhookPayload(body);

    if (!validation.valid) {
      logger.warn({ requestId, error: validation.error }, 'Invalid Maximo webhook payload');
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, validation.error, requestId),
        400
      );
    }

    payload = validation.data;
  } catch (err) {
    logger.warn({ requestId, error: err }, 'Failed to parse Maximo webhook payload');
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON payload', requestId),
      400
    );
  }

  logger.info(
    { requestId, event: payload.event, wonum: payload.wonum, status: payload.status },
    'Received Maximo webhook'
  );

  // Using imported db singleton

  // Find shadow record by Maximo WO number
  const shadowRecord = await db.query.maximoShadowRecords.findFirst({
    where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
  });

  if (!shadowRecord) {
    // Check if we have an mms_schedule_id backreference
    if (payload.mms_schedule_id && isValidUuid(payload.mms_schedule_id)) {
      // Try to find shadow record by PM schedule ID
      const shadowByPm = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, payload.mms_schedule_id),
      });

      if (shadowByPm) {
        // Update shadow record with WO number
        await db
          .update(maximoShadowRecords)
          .set({
            maximoWoNum: payload.wonum,
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, shadowByPm.id));

        logger.info(
          { requestId, shadowRecordId: shadowByPm.id, wonum: payload.wonum },
          'Associated Maximo WO number with existing shadow record'
        );
      }
    }

    // If still no shadow record, log and return success (idempotent)
    if (!shadowRecord) {
      logger.info(
        { requestId, wonum: payload.wonum },
        'No shadow record found for Maximo WO - may be untracked in MMS'
      );

      return c.json(
        success({
          received: true,
          processed: false,
          reason: 'No matching shadow record found',
          wonum: payload.wonum,
        }),
        200
      );
    }
  }

  // Process based on event type
  try {
    let action = 'none';
    let mmsStatusUpdated = false;
    let pmLocked = false;

    if (payload.event === 'wo_status_changed' && payload.status) {
      // Get the current shadow record (refreshed)
      const currentShadow = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
      });

      if (currentShadow) {
        const previousMaximoData = currentShadow.maximoData as { status?: string } | null;
        const previousStatus = previousMaximoData?.status;

        // Update shadow record with new Maximo data
        await db
          .update(maximoShadowRecords)
          .set({
            maximoData: {
              status: payload.status,
              actualStart: payload.actstart,
              actualFinish: payload.actfinish,
              actualLabor: payload.actlabhrs,
              changeDate: payload.changedate,
            },
            lastSyncAt: new Date(),
            syncStatus: 'SYNCED',
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, currentShadow.id));

        // Map Maximo status to MMS status
        const mmsStatus = MAXIMO_TO_MMS_STATUS[payload.status];

        // Update PM schedule status
        const pmRecord = await db.query.pmSchedule.findFirst({
          where: eq(pmSchedule.id, currentShadow.pmScheduleId),
        });

        if (pmRecord) {
          const isLocked = LOCKED_MAXIMO_STATUSES.includes(payload.status);

          // Update PM schedule
          await db
            .update(pmSchedule)
            .set({
              status: mmsStatus,
              isLocked: isLocked,
              actualStartDate: payload.actstart ? payload.actstart.split('T')[0] : pmRecord.actualStartDate,
              actualEndDate: payload.actfinish ? payload.actfinish.split('T')[0] : pmRecord.actualEndDate,
              actualHours: payload.actlabhrs !== undefined
                ? payload.actlabhrs.toString()
                : pmRecord.actualHours,
              updatedAt: new Date(),
            })
            .where(eq(pmSchedule.id, pmRecord.id));

          mmsStatusUpdated = true;
          pmLocked = isLocked;

          logger.info(
            {
              requestId,
              pmScheduleId: pmRecord.id,
              previousStatus,
              newStatus: payload.status,
              mmsStatus,
              isLocked,
            },
            'Updated PM schedule from Maximo webhook'
          );
        }

        action = 'status_updated';
      }
    } else if (payload.event === 'wo_cancelled') {
      // Handle work order cancellation
      const currentShadow = await db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
      });

      if (currentShadow) {
        await db
          .update(maximoShadowRecords)
          .set({
            maximoData: {
              status: 'CAN',
              changeDate: payload.changedate,
            },
            syncStatus: 'SYNCED',
            updatedAt: new Date(),
          })
          .where(eq(maximoShadowRecords.id, currentShadow.id));

        // Update PM schedule to CANCELLED and locked
        await db
          .update(pmSchedule)
          .set({
            status: 'CANCELLED',
            isLocked: true,
            updatedAt: new Date(),
          })
          .where(eq(pmSchedule.id, currentShadow.pmScheduleId));

        action = 'wo_cancelled';
        mmsStatusUpdated = true;
        pmLocked = true;

        logger.info(
          { requestId, pmScheduleId: currentShadow.pmScheduleId, wonum: payload.wonum },
          'PM cancelled from Maximo webhook'
        );
      }
    }

    const durationMs = Date.now() - startTime;

    return c.json(
      success({
        received: true,
        processed: true,
        action,
        wonum: payload.wonum,
        event: payload.event,
        mmsStatusUpdated,
        pmLocked,
        durationMs,
      }),
      200
    );
  } catch (err) {
    logger.error({ requestId, error: err, wonum: payload.wonum }, 'Failed to process Maximo webhook');
    return c.json(
      error(
        ErrorCodes.INTERNAL_ERROR,
        'Failed to process webhook',
        requestId,
        { wonum: payload.wonum }
      ),
      500
    );
  }
});

// =============================================================================
// Sync Operations
// =============================================================================

/**
 * GET /integration/sync/stats
 *
 * Get Maximo sync statistics.
 *
 * Returns counts of shadow records by status, last sync timestamps,
 * and circuit breaker state.
 */
integrationRoutes.get('/integration/sync/stats', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const stats = await service.getSyncStats();

    return c.json(
