integrationRoutes.get('/integration/polling/stats', async (c) => {
  const requestId = getRequestId(c);
  const depotId = c.req.query('depotId');

  try {
    const pollingService = getPollingService();
    const stats = await pollingService.getPollingStats(depotId);

    return c.json(
      success({
        webhookHealth: {
          ...stats.webhookHealth,
          lastReceivedAt: stats.webhookHealth.lastReceivedAt?.toISOString() ?? null,
        },
        config: stats.config,
        metrics: {
          totalPollsExecuted: stats.totalPollsExecuted,
          totalDuplicatesPrevented: stats.totalDuplicatesPrevented,
          totalFallbackActivations: stats.totalFallbackActivations,
        },
