/**
 * Get metrics output for Prometheus scraping
 */
export async function getMetrics(): Promise<string> {
  return registry.metrics();
}

/**
 * Get content type for metrics response
 */
export function getMetricsContentType(): string {
  return registry.contentType;
}

/**
 * Reset all metrics (useful for testing)
 */
export function resetMetrics(): void {
  registry.resetMetrics();
}

/**
 * HTTP middleware helper - measure request duration
 */
export function measureHttpRequest(
  method: string,
  path: string,
  status: number,
  durationMs: number
): void {
  const labels = { method, path, status: String(status) };
  httpRequestsTotal.inc(labels);
  httpRequestDuration.observe(labels, durationMs / 1000);
}

/**
 * Queue job helper - record job completion
 */
export function recordQueueJob(
  queue: string,
  jobName: string,
  status: 'completed' | 'failed',
  durationMs: number
): void {
  queueJobsTotal.inc({ queue, status });
  queueJobDuration.observe({ queue, job_name: jobName }, durationMs / 1000);
}

/**
 * Optimizer helper - record solve completion
 */
export function recordOptimizerRun(
  solverType: 'cpsat' | 'fallback',
  status: 'optimal' | 'feasible' | 'infeasible' | 'timeout' | 'error',
  durationMs: number,
  objective?: number
): void {
  optimizerRunsTotal.inc({ solver_type: solverType, status });
  optimizerSolveSeconds.observe({ solver_type: solverType, status }, durationMs / 1000);
  if (objective !== undefined) {
    optimizerObjectiveValue.set({ solver_type: solverType }, objective);
  }
}

