/**
 * Record Maximo sync operation
 */
export function recordMaximoSync(
  operation: 'push' | 'pull' | 'full' | 'polling',
  status: 'success' | 'failure' | 'partial',
  durationMs: number,
  recordsProcessed: number,
  recordsUpdated: number
): void {
  maximoMetrics.syncRequestsTotal.inc({ operation, status });
  maximoMetrics.syncDuration.observe({ operation }, durationMs / 1000);
  maximoMetrics.syncRecordsProcessed.inc({ operation, result: 'processed' }, recordsProcessed);
  maximoMetrics.syncRecordsProcessed.inc({ operation, result: 'updated' }, recordsUpdated);
}

/**
 * Record webhook received
 */
export function recordMaximoWebhook(
  eventType: string,
  status: 'success' | 'failure',
  durationMs: number,
  depotId?: string
): void {
  maximoMetrics.webhooksReceived.inc({ event_type: eventType, status });
  maximoMetrics.webhookProcessingDuration.observe({ event_type: eventType }, durationMs / 1000);
  if (status === 'success') {
    maximoMetrics.webhookLastReceivedAt.set({ depot_id: depotId ?? 'global' }, Date.now() / 1000);
  }
}

/**
 * Record polling fallback activation
 */
export function recordPollingFallbackActivation(reason: 'webhook_timeout' | 'manual' | 'circuit_breaker'): void {
  maximoMetrics.pollingTriggered.inc({ trigger_reason: reason });
}

/**
 * Update sync mode metric
 */
export function updateSyncModeMetric(depotId: string, mode: 'WEBHOOK' | 'POLLING' | 'HYBRID'): void {
  const modeValue = mode === 'WEBHOOK' ? 0 : mode === 'POLLING' ? 1 : 2;
  maximoMetrics.syncMode.set({ depot_id: depotId }, modeValue);
  maximoMetrics.pollingFallbackActive.set({ depot_id: depotId }, mode !== 'WEBHOOK' ? 1 : 0);
}

// =============================================================================
// Rate Limiting Metrics
// =============================================================================

/**
 * Rate limiting metrics for monitoring and alerting
 *
 * @see specs/005-api.md - Rate Limiting: 100 requests/minute per user
 */
export const rateLimitMetrics = {
  /**
   * Total rate limit checks performed
   */
  rateLimitChecks: new Counter({
    name: 'mms_rate_limit_checks_total',
    help: 'Total number of rate limit checks performed',
    labelNames: ['identifier_type', 'result'] as const,
    registers: [registry],
  }),

  /**
   * Rate limit exceeded events
   */
  rateLimitExceeded: new Counter({
    name: 'mms_rate_limit_exceeded_total',
    help: 'Total number of requests rejected due to rate limiting',
    labelNames: ['identifier_type'] as const,
    registers: [registry],
  }),

  /**
   * Current rate limit window usage per identifier
   */
  rateLimitUsage: new Gauge({
    name: 'mms_rate_limit_usage',
    help: 'Current rate limit usage percentage',
    labelNames: ['identifier_type'] as const,
    registers: [registry],
  }),
};

/**
 * Record rate limit check result
 */
export function recordRateLimitCheck(
  identifierType: 'user' | 'ip',
  result: 'allowed' | 'exceeded'
): void {
  rateLimitMetrics.rateLimitChecks.inc({ identifier_type: identifierType, result });
  if (result === 'exceeded') {
    rateLimitMetrics.rateLimitExceeded.inc({ identifier_type: identifierType });
  }
}
